//go:build contract

// Provider verification for pre-processor's PreProcessorService Connect-RPC.
//
// Replays the pact generated by alt-backend (consumer) against a stub HTTP
// server that mirrors the 3 Connect-RPC endpoints alt-backend invokes:
//   - Summarize          — synchronous summarize-on-demand
//   - QueueSummarize     — async enqueue returning jobId
//   - GetSummarizeStatus — poll for completion + summary
//
// Authentication is handled at the transport layer (mTLS peer-identity
// allowlist) in production; the stub accepts any caller because the pact
// replay does not present a TLS peer.
package contract

import (
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/http"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/pact-foundation/pact-go/v2/models"
	"github.com/pact-foundation/pact-go/v2/provider"
	"github.com/stretchr/testify/require"
)

const (
	preProcessorProviderName      = "pre-processor"
	altBackendPreProcessorPactDir = "../../../../alt-backend/pacts"
	altBackendPreProcessorPact    = "alt-backend-pre-processor.json"
)

// startPreProcessorProviderStub starts a minimal HTTP server that mirrors
// the Connect-RPC (JSON wire format) endpoints alt-backend exercises.
func startPreProcessorProviderStub(t *testing.T) int {
	t.Helper()

	mux := http.NewServeMux()

	// POST /services.preprocessor.v2.PreProcessorService/Summarize
	mux.HandleFunc("/services.preprocessor.v2.PreProcessorService/Summarize",
		func(w http.ResponseWriter, r *http.Request) {
			if r.Method != http.MethodPost {
				w.WriteHeader(http.StatusMethodNotAllowed)
				return
			}
			_, _ = io.Copy(io.Discard, r.Body)
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(map[string]interface{}{
				"articleId": "article-123",
				"success":   true,
				"summary":   "This is a generated summary.",
			})
		})

	// POST /services.preprocessor.v2.PreProcessorService/QueueSummarize
	mux.HandleFunc("/services.preprocessor.v2.PreProcessorService/QueueSummarize",
		func(w http.ResponseWriter, r *http.Request) {
			if r.Method != http.MethodPost {
				w.WriteHeader(http.StatusMethodNotAllowed)
				return
			}
			_, _ = io.Copy(io.Discard, r.Body)
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(map[string]interface{}{
				"jobId":   "job-001",
				"message": "Job queued successfully",
				"status":  "pending",
			})
		})

	// POST /services.preprocessor.v2.PreProcessorService/GetSummarizeStatus
	mux.HandleFunc("/services.preprocessor.v2.PreProcessorService/GetSummarizeStatus",
		func(w http.ResponseWriter, r *http.Request) {
			if r.Method != http.MethodPost {
				w.WriteHeader(http.StatusMethodNotAllowed)
				return
			}
			_, _ = io.Copy(io.Discard, r.Body)
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(map[string]interface{}{
				"articleId": "article-456",
				"jobId":     "job-789",
				"status":    "completed",
				"summary":   "Generated summary text",
			})
		})

	ln, err := net.Listen("tcp", "127.0.0.1:0")
	require.NoError(t, err)
	t.Cleanup(func() { _ = ln.Close() })

	go func() { _ = http.Serve(ln, mux) }()

	return ln.Addr().(*net.TCPAddr).Port
}

// TestVerifyAltBackendContract verifies pre-processor satisfies the Connect-RPC
// contract alt-backend generated (Summarize / QueueSummarize / GetSummarizeStatus).
func TestVerifyAltBackendContract(t *testing.T) {
	pactFile := filepath.Join(altBackendPreProcessorPactDir, altBackendPreProcessorPact)

	brokerURL := os.Getenv("PACT_BROKER_BASE_URL")
	if brokerURL == "" {
		if _, err := os.Stat(pactFile); os.IsNotExist(err) {
			t.Skipf("No Broker URL set and pact file not found: %s. "+
				"Run alt-backend consumer tests first.", pactFile)
		}
	}

	port := startPreProcessorProviderStub(t)

	verifyRequest := provider.VerifyRequest{
		Provider:        preProcessorProviderName,
		ProviderBaseURL: fmt.Sprintf("http://127.0.0.1:%d", port),
		StateHandlers: models.StateHandlers{
			"an article exists with id article-123": func(setup bool, s models.ProviderState) (models.ProviderStateResponse, error) {
				return nil, nil
			},
			"the summarization queue is available": func(setup bool, s models.ProviderState) (models.ProviderStateResponse, error) {
				return nil, nil
			},
			"a completed summarize job exists with id job-789": func(setup bool, s models.ProviderState) (models.ProviderStateResponse, error) {
				return nil, nil
			},
		},
	}

	if brokerURL != "" {
		verifyRequest.BrokerURL = brokerURL
		verifyRequest.BrokerUsername = os.Getenv("PACT_BROKER_USERNAME")
		verifyRequest.BrokerPassword = os.Getenv("PACT_BROKER_PASSWORD")
		// Per Pact's recommended provider-verification configuration, pull
		// both the consumer's main-branch pacts and any pacts currently
		// deployed/released. Without the deployedOrReleased selector the
		// broker never records a verification for the currently-deployed
		// consumer version, so can-i-deploy returns "unknown" after a SHA
		// bump even when the pact contents are unchanged.
		verifyRequest.ConsumerVersionSelectors = []provider.Selector{
			&provider.ConsumerVersionSelector{Consumer: "alt-backend", MainBranch: true},
			&provider.ConsumerVersionSelector{Consumer: "alt-backend", DeployedOrReleased: true},
		}
		if ver := os.Getenv("PACT_PROVIDER_VERSION"); ver != "" {
			verifyRequest.ProviderVersion = ver
			verifyRequest.PublishVerificationResults = true
		}
		if branch := os.Getenv("PACT_PROVIDER_BRANCH"); branch != "" {
			verifyRequest.ProviderBranch = branch
		}
		if os.Getenv("PACT_DISABLE_PENDING") != "true" {
			verifyRequest.EnablePending = true
		}
		if since := os.Getenv("PACT_INCLUDE_WIP_SINCE"); since != "" {
			if t, err := time.Parse(time.RFC3339, since); err == nil {
				verifyRequest.IncludeWIPPactsSince = &t
			}
		}
	} else {
		verifyRequest.PactFiles = []string{pactFile}
	}

	verifier := provider.NewVerifier()
	err := verifier.VerifyProvider(t, verifyRequest)
	require.NoError(t, err)
}
